-- Phase 1 demo seed data for SCN International (20 products).
insert into probuy.primary_sources (code, name, is_active)
values ('SCN', 'SCN International', true)
on conflict (code) do update set name = excluded.name, is_active = excluded.is_active, updated_at = now();
with scn_source as (
    select id from probuy.primary_sources where code = 'SCN'
), seed_locations(code, name, province, country, raw_data) as (
    values
    ('SCN-CA', 'SCN Canada Pricing', 'National', 'CA', '{"source": "price_list_example.xlsx", "notes": "Pricing list scope"}'::jsonb)
    ,('MTL', 'Montreal Distribution Centre', 'QC', 'CA', '{"source": "inventory_list_example.xlsx", "sheet": "MTL"}'::jsonb)
    ,('VAN', 'Vancouver Distribution Centre', 'BC', 'CA', '{"source": "inventory_list_example.xlsx", "sheet": "VAN"}'::jsonb)
    ,('EDM', 'Edmonton Distribution Centre', 'AB', 'CA', '{"source": "inventory_list_example.xlsx", "sheet": "EDM"}'::jsonb)
)
insert into probuy.source_locations (source_id, code, name, province, country, is_active, raw_data)
select s.id, l.code, l.name, l.province, l.country, true, l.raw_data
from seed_locations l cross join scn_source s
on conflict (source_id, code) do update
set name = excluded.name, province = excluded.province, country = excluded.country, is_active = excluded.is_active, raw_data = excluded.raw_data, updated_at = now();

