insert into probuy.source_products (source_id, source_product_key, source_model_no, brand, manufacturer, product_title_en, description_en, category_en, unit_description_en, product_url, image_url, is_active, raw_data)
select s.id, p.source_product_key, p.source_model_no, p.brand, p.manufacturer, p.product_title_en, p.description_en, p.category_en, p.unit_description_en, p.product_url, p.image_url, true, p.raw_data
from seed_products p cross join scn_source s
on conflict (source_id, source_product_key) do update
set source_model_no = excluded.source_model_no, brand = excluded.brand, manufacturer = excluded.manufacturer, product_title_en = excluded.product_title_en, description_en = excluded.description_en, category_en = excluded.category_en, unit_description_en = excluded.unit_description_en, product_url = excluded.product_url, image_url = excluded.image_url, is_active = excluded.is_active, raw_data = excluded.raw_data, updated_at = now();

