insert into probuy.product_attribute_values (source_product_id, attribute_id, value_text, unit, raw_data)
select sp.id, ad.id, sav.value_text, null, sav.raw_data
from seed_attribute_values sav
join scn_source s on true
join probuy.source_products sp on sp.source_id = s.id and sp.source_product_key = sav.source_product_key
join probuy.attribute_definitions ad on ad.display_name = sav.display_name
on conflict (source_product_id, attribute_id) do update
set value_text = excluded.value_text, unit = excluded.unit, raw_data = excluded.raw_data, updated_at = now();

